#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int T,n,a[N<<1],sum[3];
char s[N],t[N];

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d",&n);
        scanf("%s",s+1);
        scanf("%s",t+1);
        for(int i=1;i<=n;i++){
            if(s[i]=='P') a[i*2-1]=0;
            else if(s[i]=='V') a[i*2-1]=1;
            else a[i*2-1]=2;
        }
        for(int i=1;i<=n;i++){
            if(t[i]=='P') a[i*2]=0;
            else if(t[i]=='V') a[i*2]=1;
            else a[i*2]=2;
        }
        sum[0]=sum[1]=sum[2]=0;
        bool flag=false;
        for(int i=1;i<=2*n;i++){
            sum[a[i]]++;
            if(sum[0]==sum[1] && sum[1]==sum[2]){
                if(i%2) flag=true;
                break;
            }
        }
        if(flag){
            puts("0");
            continue;
        }
        sum[0]=sum[1]=sum[2]=0;
        flag=false;
        bool lst=false,b[3]={false,false,false};
        for(int i=1;i<=2*n;i++){
            sum[a[i]]++;
            if(sum[0]==sum[1] && sum[1]==sum[2] && i%6==0)
                lst=true;
            if(i%6==0 && abs(sum[0]-i/3)+abs(sum[1]-i/3)+abs(sum[2]-i/3)==2 && lst){
                if(sum[0]==i/3) b[0]=1;
                else if(sum[1]==i/3) b[1]=1;
                else b[2]=1;
            }
            if(i%6==3 && abs(sum[0]-i/3)+abs(sum[1]-i/3)+abs(sum[2]-i/3)==2){
                if(sum[0]==i/3 && !b[0]) flag=1;
                else if(sum[1]==i/3 && !b[1]) flag=1;
                else if(sum[2]==i/3 && !b[2]) flag=1;
                if(flag)
                    break;
            }
        }
        if(flag)
            puts("1");
        else
            puts("2");
    }
    return 0;
}
